import React, { useState, useRef, useEffect } from 'react';
import { View, StyleSheet, FlatList, TouchableOpacity, Animated, Dimensions } from 'react-native';
import { Text } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';

const { width } = Dimensions.get('window');

export default function OrdersScreen() {
  const [filter, setFilter] = useState('all');
  const headerAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.timing(headerAnim, { toValue: 1, duration: 500, useNativeDriver: true }).start();
  }, []);

  const orders = [
    {
      id: 1, orderNumber: 'ORD-2024-001', date: '2024-01-28', farmer: 'Rajesh Kumar',
      products: [{ name: 'Fresh Tomatoes', quantity: 2, price: 80 }, { name: 'Organic Spinach', quantity: 1, price: 30 }],
      total: 110, status: 'Delivered', deliveryDate: '2024-01-29',
    },
    {
      id: 2, orderNumber: 'ORD-2024-002', date: '2024-01-30', farmer: 'Priya Sharma',
      products: [{ name: 'Fresh Carrots', quantity: 3, price: 105 }],
      total: 105, status: 'In Transit', estimatedDelivery: '2024-01-31',
    },
    {
      id: 3, orderNumber: 'ORD-2024-003', date: '2024-01-31', farmer: 'Amit Patil',
      products: [{ name: 'Fresh Apples', quantity: 2, price: 240 }],
      total: 240, status: 'Processing', estimatedDelivery: '2024-02-01',
    },
  ];

  const filteredOrders = orders.filter((o) => {
    if (filter === 'all') return true;
    if (filter === 'active') return o.status === 'Processing' || o.status === 'In Transit';
    if (filter === 'completed') return o.status === 'Delivered';
    return true;
  });

  const getStatusConfig = (status) => {
    switch (status) {
      case 'Delivered': return { gradient: ['#00C853', '#00E676'], icon: 'check-circle', color: '#00C853' };
      case 'In Transit': return { gradient: ['#2196F3', '#42A5F5'], icon: 'truck-delivery', color: '#42A5F5' };
      case 'Processing': return { gradient: ['#FF9800', '#FFB74D'], icon: 'clock-outline', color: '#FFB74D' };
      default: return { gradient: ['#666', '#888'], icon: 'help-circle', color: '#888' };
    }
  };

  const filters = [
    { key: 'all', label: 'All', icon: 'format-list-bulleted' },
    { key: 'active', label: 'Active', icon: 'truck-fast' },
    { key: 'completed', label: 'Done', icon: 'check-all' },
  ];

  const renderOrder = ({ item, index }) => <AnimatedOrderCard order={item} index={index} getStatusConfig={getStatusConfig} />;

  return (
    <LinearGradient colors={['#0a1a0f', '#0d2818', '#0a1a0f']} style={styles.container}>
      {/* Header */}
      <Animated.View style={[styles.header, { opacity: headerAnim }]}>
        <Text style={styles.headerTitle}>My Orders</Text>
        <Text style={styles.headerSub}>{filteredOrders.length} orders</Text>
      </Animated.View>

      {/* Filter Tabs */}
      <View style={styles.filterContainer}>
        {filters.map((f) => (
          <TouchableOpacity
            key={f.key}
            activeOpacity={0.7}
            style={[styles.filterTab, filter === f.key && styles.filterTabActive]}
            onPress={() => setFilter(f.key)}
          >
            <Icon name={f.icon} size={16} color={filter === f.key ? '#0a1a0f' : 'rgba(255,255,255,0.5)'} />
            <Text style={[styles.filterLabel, filter === f.key && styles.filterLabelActive]}>{f.label}</Text>
          </TouchableOpacity>
        ))}
      </View>

      <FlatList
        data={filteredOrders}
        renderItem={renderOrder}
        keyExtractor={(item) => item.id.toString()}
        contentContainerStyle={styles.listContainer}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          <View style={styles.emptyContainer}>
            <Icon name="clipboard-list-outline" size={60} color="rgba(255,255,255,0.15)" />
            <Text style={styles.emptyText}>No orders found</Text>
          </View>
        }
      />
    </LinearGradient>
  );
}

function AnimatedOrderCard({ order, index, getStatusConfig }) {
  const anim = useRef(new Animated.Value(0)).current;
  useEffect(() => {
    Animated.spring(anim, { toValue: 1, delay: index * 120, tension: 50, friction: 8, useNativeDriver: true }).start();
  }, []);

  const config = getStatusConfig(order.status);

  return (
    <Animated.View style={{ opacity: anim, transform: [{ translateY: anim.interpolate({ inputRange: [0, 1], outputRange: [40, 0] }) }] }}>
      <View style={styles.orderCard}>
        <View style={styles.orderGlass}>
          {/* Header Row */}
          <View style={styles.orderHeader}>
            <View>
              <Text style={styles.orderNumber}>{order.orderNumber}</Text>
              <Text style={styles.orderDate}>{order.date}</Text>
            </View>
            <LinearGradient colors={config.gradient} style={styles.statusBadge}>
              <Icon name={config.icon} size={12} color="#fff" />
              <Text style={styles.statusText}>{order.status}</Text>
            </LinearGradient>
          </View>

          {/* Farmer */}
          <View style={styles.farmerRow}>
            <Icon name="account" size={14} color="rgba(255,255,255,0.4)" />
            <Text style={styles.farmerName}>{order.farmer}</Text>
          </View>

          {/* Products */}
          <View style={styles.productsBox}>
            {order.products.map((product, i) => (
              <View key={i} style={styles.productRow}>
                <Text style={styles.productName}>{product.name} × {product.quantity}</Text>
                <Text style={styles.productPrice}>₹{product.price}</Text>
              </View>
            ))}
          </View>

          {/* Footer */}
          <View style={styles.orderFooter}>
            <View>
              <Text style={styles.totalLabel}>Total</Text>
              <Text style={styles.totalAmount}>₹{order.total}</Text>
            </View>
            {order.status !== 'Delivered' && (
              <View style={styles.deliveryInfo}>
                <Icon name="clock-outline" size={13} color="rgba(255,255,255,0.4)" />
                <Text style={styles.deliveryText}>ETA: {order.estimatedDelivery}</Text>
              </View>
            )}
          </View>

          {/* Timeline dots */}
          <View style={styles.timeline}>
            <View style={[styles.timelineDot, { backgroundColor: '#00C853' }]} />
            <View style={[styles.timelineLine, { backgroundColor: order.status === 'Processing' ? 'rgba(255,255,255,0.1)' : '#00C853' }]} />
            <View style={[styles.timelineDot, { backgroundColor: order.status === 'Processing' ? 'rgba(255,255,255,0.1)' : config.color }]} />
            <View style={[styles.timelineLine, { backgroundColor: order.status === 'Delivered' ? '#00C853' : 'rgba(255,255,255,0.1)' }]} />
            <View style={[styles.timelineDot, { backgroundColor: order.status === 'Delivered' ? '#00C853' : 'rgba(255,255,255,0.1)' }]} />
          </View>
          <View style={styles.timelineLabels}>
            <Text style={styles.timelineLabel}>Placed</Text>
            <Text style={styles.timelineLabel}>Shipped</Text>
            <Text style={styles.timelineLabel}>Delivered</Text>
          </View>
        </View>
      </View>
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: { paddingHorizontal: 24, paddingTop: 60, paddingBottom: 8 },
  headerTitle: { fontSize: 28, fontWeight: '800', color: '#fff', letterSpacing: -0.5 },
  headerSub: { fontSize: 13, color: 'rgba(255,255,255,0.4)', marginTop: 4 },
  filterContainer: { flexDirection: 'row', paddingHorizontal: 20, marginTop: 12, marginBottom: 16 },
  filterTab: { flex: 1, flexDirection: 'row', alignItems: 'center', justifyContent: 'center', paddingVertical: 12, borderRadius: 14, marginHorizontal: 4, backgroundColor: 'rgba(255,255,255,0.05)', borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)' },
  filterTabActive: { backgroundColor: '#00C853', borderColor: '#00C853' },
  filterLabel: { fontSize: 13, fontWeight: '600', color: 'rgba(255,255,255,0.5)', marginLeft: 6 },
  filterLabelActive: { color: '#0a1a0f' },
  listContainer: { paddingBottom: 100 },
  orderCard: { paddingHorizontal: 20, marginBottom: 16 },
  orderGlass: { backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: 20, padding: 18, borderWidth: 1, borderColor: 'rgba(255,255,255,0.06)' },
  orderHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 },
  orderNumber: { fontSize: 15, fontWeight: '700', color: '#fff' },
  orderDate: { fontSize: 11, color: 'rgba(255,255,255,0.3)', marginTop: 3 },
  statusBadge: { flexDirection: 'row', alignItems: 'center', paddingHorizontal: 12, paddingVertical: 6, borderRadius: 10 },
  statusText: { fontSize: 11, fontWeight: '700', color: '#fff', marginLeft: 4 },
  farmerRow: { flexDirection: 'row', alignItems: 'center', marginBottom: 14 },
  farmerName: { fontSize: 13, color: 'rgba(255,255,255,0.5)', marginLeft: 6 },
  productsBox: { backgroundColor: 'rgba(255,255,255,0.04)', borderRadius: 12, padding: 12, marginBottom: 14 },
  productRow: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: 4 },
  productName: { fontSize: 13, color: 'rgba(255,255,255,0.6)' },
  productPrice: { fontSize: 13, color: 'rgba(255,255,255,0.5)' },
  orderFooter: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: 16 },
  totalLabel: { fontSize: 11, color: 'rgba(255,255,255,0.3)' },
  totalAmount: { fontSize: 22, fontWeight: '800', color: '#00C853', marginTop: 2 },
  deliveryInfo: { flexDirection: 'row', alignItems: 'center' },
